<?php
require_once dirname(__DIR__) . '/includes/functions.php';
employeePortalGuard();$user=currentUser();$pdo=getDB();$employee=employeeForCurrentUser($pdo,$user);if(!$employee){siteHeader('My Documents','login');echo '<div class="alert alert-warning">No employee profile is linked to your email.</div>';siteFooter();exit;}
if($_SERVER['REQUEST_METHOD']==='POST'){try{$upload=uploadAdminDocument('employee_file','employee-documents');if(!$upload){throw new RuntimeException('Choose a file.');}createEmployeeDocument($pdo,(int)$employee['id'],$upload,trim((string)$_POST['document_type']),trim((string)$_POST['expiry_date']),trim((string)$_POST['notes']));flash('success','Document uploaded.');}catch(Throwable $e){flash('error',$e->getMessage());}redirect(SITE_URL.'/employee/documents.php');}
$docs=$pdo->prepare('SELECT * FROM '.table('employee_documents').' WHERE employee_id=? ORDER BY created_at DESC');$docs->execute([(int)$employee['id']]);$docs=$docs->fetchAll();
siteHeader('My Documents','login');
?>
<h1 class="mb-4">My Documents</h1><div class="row g-4"><div class="col-lg-5"><form method="post" enctype="multipart/form-data" class="form-card"><h2 class="h4">Upload Document</h2><input class="form-control mb-3" name="document_type" placeholder="Passport, visa, certificate, license"><input class="form-control mb-3" type="date" name="expiry_date"><input class="form-control mb-3" type="file" name="employee_file" required><textarea class="form-control mb-3" name="notes" rows="3" placeholder="Notes"></textarea><button class="btn btn-brand">Upload</button></form></div><div class="col-lg-7"><div class="table-card table-responsive"><table class="table"><thead><tr><th>Document</th><th>File</th><th>Expiry</th><th>Status</th></tr></thead><tbody><?php foreach($docs as $d): ?><tr><td><strong><?php echo esc($d['document_type']); ?></strong></td><td><?php echo esc($d['file_name']); ?></td><td><?php echo esc($d['expiry_date']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($d['status'])); ?>"><?php echo esc($d['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php siteFooter(); ?>